script:
// --- بداية الكود ---

frappe.ui.form.on('Building Survey', {
    refresh: function(frm) {

        // إخفاء الحقول الفردية فقط لتجنب إخفاء قسم التصميم بالكامل
        frm.toggle_display([
            'full_name', 'phone', 'email', 'current_residence', 'city',
            'project_location', 'has_sketch', 'has_autocad',
            'size_family', 'couples', 'grandchildren',
            'girls_under_10', 'boys_under_10',
            'girls_above_14', 'boys_above_14', 'haya'
        ], false);

        render_custom_survey(frm);
    }
});

function render_custom_survey(frm) {

    let wrapper = frm.get_field('survey_ui');
    if (!wrapper) return;

    // 1. CSS
    let css = `
    <style>
        .custom-survey-wrapper {
            direction: rtl;
            font-family: 'Tajawal', 'Cairo', sans-serif;
            background-color: #f8f9fa;
            padding: 20px;
            color: #333;
        }
        .survey-header-main {
            background-color: #a8b2bc;
            color: #2c3e50;
            padding: 15px;
            font-size: 24px;
            font-weight: bold;
            text-align: right;
            border-radius: 8px 8px 0 0;
            margin-bottom: 20px;
            display: flex;
            align-items: center;
        }
        .survey-section {
            border: 2px solid #5c6c7f;
            border-radius: 8px;
            background: #fff;
            margin-bottom: 20px;
            overflow: hidden;
        }
        .section-title {
            background-color: #5c6c7f;
            color: #fff;
            padding: 10px 15px;
            font-size: 18px;
            font-weight: bold;
            display: inline-block;
            border-radius: 0 0 0 8px;
        }
        .section-content {
            padding: 15px;
        }
        .form-row-custom {
            display: flex;
            align-items: center;
            margin-bottom: 12px;
            border-bottom: 1px dashed #e2e8f0;
            padding-bottom: 8px;
        }
        .form-row-custom label {
            flex: 1;
            font-weight: bold;
            color: #2c3e50;
            margin: 0;
            font-size: 14px;
        }
        .form-row-custom input,
        .form-row-custom select {
            flex: 2;
            border: none;
            border-bottom: 1px solid #ccc;
            background: transparent;
            padding: 5px;
            outline: none;
            font-family: inherit;
        }
        .grid-2-cols {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 15px;
        }
    </style>
    `;

    // 2. HTML
    let html = `
    <div class="custom-survey-wrapper">

        <div class="survey-header-main">
            نموذج استبيان مبنى سكني
        </div>

        <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;">

            <!-- المشروع -->
            <div>
                <div class="survey-section">
                    <div class="section-title">معلومات خاصة بالمشروع</div>
                    <div class="section-content">

                        <div class="form-row-custom">
                            <label>أين يقع المشروع</label>
                            <input id="ui_project_location" value="${frm.doc.project_location || ''}">
                        </div>

                        <div class="form-row-custom">
                            <label>هل يوجد رسم كروكي</label>
                            <select id="ui_has_sketch">
                                <option ${frm.doc.has_sketch == "نعم" ? "selected" : ""}>نعم</option>
                                <option ${frm.doc.has_sketch == "لا" ? "selected" : ""}>لا</option>
                            </select>
                        </div>

                        <div class="form-row-custom">
                            <label>AutoCAD</label>
                            <select id="ui_has_autocad">
                                <option ${frm.doc.has_autocad == "نعم" ? "selected" : ""}>نعم</option>
                                <option ${frm.doc.has_autocad == "لا" ? "selected" : ""}>لا</option>
                            </select>
                        </div>

                    </div>
                </div>
            </div>

            <!-- التواصل -->
            <div>
                <div class="survey-section">
                    <div class="section-title">معلومات التواصل</div>
                    <div class="section-content">

                        <div class="form-row-custom">
                            <label>الإسم</label>
                            <input id="ui_full_name" value="${frm.doc.full_name || ''}">
                        </div>

                        <div class="form-row-custom">
                            <label>الهاتف</label>
                            <input id="ui_phone" value="${frm.doc.phone || ''}">
                        </div>

                        <div class="form-row-custom">
                            <label>الإيميل</label>
                            <input id="ui_email" value="${frm.doc.email || ''}">
                        </div>

                        <div class="form-row-custom">
                            <label>السكن</label>
                            <input id="ui_current_residence" value="${frm.doc.current_residence || ''}">
                        </div>

                        <div class="form-row-custom">
                            <label>المدينة</label>
                            <input id="ui_city" value="${frm.doc.city || ''}">
                        </div>

                    </div>
                </div>
            </div>

        </div>

    </div>
    `;

    wrapper.$wrapper.html(css + html);

    bind_survey_events(frm, wrapper.$wrapper);
}

function bind_survey_events(frm, $wrapper) {

    const fields = [
        'full_name','phone','email','current_residence','city',
        'project_location'
    ];

    fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    const selects = ['has_sketch','has_autocad'];

    selects.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });
}

// --- نهاية الكود ---

// يمكنك وضع هذا الكود في ملف JS مخصص أو حقنه عبر Client Script عام
frappe.provide("frappe.ui");

$(document).ready(function() {
    // كود CSS المخصص لكروت الأرقام بهوية الأبيض والأسود
    const numberCardTheme = `
        /* استهداف حاوية كرت الأرقام */
        .widget.number-widget-box,
        .widget.number-card {
            background-color: #ffffff !important;
            border: 1px solid #e5e5e5 !important;
            border-bottom: 4px solid #000000 !important; /* خط هندسي أسود سفلي */
            border-radius: 8px !important;
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.02) !important;
            transition: all 0.3s ease !important;
            position: relative;
            overflow: hidden;
        }

        /* تأثير التحويم (Hover) لإعطاء ديناميكية مودرن */
        .widget.number-widget-box:hover,
        .widget.number-card:hover {
            transform: translateY(-4px) !important;
            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.08) !important;
            border-bottom: 4px solid #333333 !important;
        }

        /* تنسيق عنوان الكرت (المسمى) */
        .widget .widget-title,
        .widget.number-card .card-heading {
            color: #666666 !important; /* رمادي داكن للتباين */
            font-weight: 600 !important;
            font-size: 14px !important;
            letter-spacing: 0.2px;
        }

        /* تنسيق الرقم الفعلي المعروض */
        .widget .widget-value,
        .widget.number-card .number-card-value {
            color: #000000 !important; /* أسود صريح */
            font-weight: 800 !important;
            font-size: 30px !important;
            letter-spacing: -0.5px !important;
            margin-top: 8px !important;
        }

        /* تنسيق مؤشر النسبة المئوية (Indicator) إن وُجد */
        .widget .indicator-pill {
            background-color: #f4f4f5 !important;
            color: #000000 !important;
            border: 1px solid #e5e5e5 !important;
            font-weight: 600 !important;
            border-radius: 4px !important; /* زوايا شبه حادة */
        }
        
        /* تأثير خطوط معمارية خفيفة جداً في الخلفية للكرت (اختياري) */
        .widget.number-widget-box::before,
        .widget.number-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            width: 50px;
            height: 100%;
            background: repeating-linear-gradient(
                45deg,
                transparent,
                transparent 5px,
                rgba(0, 0, 0, 0.02) 5px,
                rgba(0, 0, 0, 0.02) 6px
            );
            pointer-events: none;
            opacity: 0;
            transition: opacity 0.3s ease;
        }

        .widget.number-widget-box:hover::before,
        .widget.number-card:hover::before {
            opacity: 1; /* تظهر الخطوط الهندسية عند تمرير الماوس فقط */
        }
    `;

    // حقن الكود مباشرة في رأس الصفحة
    $('<style id="custom-number-cards-theme"></style>')
        .html(numberCardTheme)
        .appendTo('head');
});

frappe.ui.form.on('Building Survey', {

    refresh: function(frm) {
        toggle_relation_field(frm);
    },

    kitchen_type: function(frm) {
        toggle_relation_field(frm);
        suggest_relation(frm);
    },

    living_type: function(frm) {
        toggle_relation_field(frm);
        suggest_relation(frm);
    },

    dining_type: function(frm) {
        suggest_relation(frm);
    }
});


// 🎯 إظهار/إخفاء relation_type بشكل صحيح
function toggle_relation_field(frm) {

    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;

    // يظهر إذا أي واحد من الاثنين Open Space
    if (
        kitchen === "مطبخ مفتوح" ||
        living === "فراغ مفتوح"
    ) {
        frm.set_df_property("relation_type", "hidden", 0);
    } else {
        frm.set_df_property("relation_type", "hidden", 1);
        frm.set_value("relation_type", "");
    }
}


// 🤖 اقتراح العلاقات
function suggest_relation(frm) {

    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;
    let dining = frm.doc.dining_type;

    // 🔥 كامل Open Space
    if (
        kitchen === "مطبخ مفتوح" &&
        living === "فراغ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "المعيشة مفتوحة على المطبخ والأكل");
        return;
    }

    // 🔥 معيشة + أكل
    if (
        living === "فراغ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "المعيشة مفتوحة على الأكل");
        return;
    }

    // 🔥 مطبخ + معيشة
    if (
        kitchen === "مطبخ مفتوح" &&
        living === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "مطبخ مفتوح على المعيشة");
        return;
    }

    // 🔥 مطبخ + أكل
    if (
        kitchen === "مطبخ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "مطبخ مفتوح على الأكل");
        return;
    }
}

frappe.ui.form.on('HD Ticket', {
    remote_desktop: function(frm) {
        // جلب الـ IP من حقل ip_device
        var ip = frm.doc.ip_device;
        
        if (ip) {
            // فتح الرابط باستخدام البروتوكول rdp://
            window.location.href = 'rdp://' + ip;
            
            // إظهار تنبيه للمستخدم
            frappe.show_alert({
                message: __('Opening Remote Desktop for ' + ip),
                indicator: 'green'
            });
        } else {
            // رسالة في حال كان الحقل فارغاً
            frappe.msgprint(__('IP Device field is empty. Please ensure the IP is captured first.'));
        }
    }
});

frappe.ui.form.on('HD Ticket', {
    refresh: function (frm) {
        // Add custom behavior if needed
    },
    remote_desktop: function (frm) {
        if (frm.doc.ip_device) {
            // رابط التطبيق المحلي الخاص بك على البورت 8088
            const local_scanner_url = `http://localhost:8088/?ip=${frm.doc.ip_device}`;
            // فتح الرابط في نافذة جديدة
            window.open(local_scanner_url, '_blank');
            frappe.show_alert({
                message: __('جاري محاولة الاتصال بـ {0}...', [frm.doc.ip_device]),
                indicator: 'blue'
            });
        } else {
            frappe.msgprint(__('يرجى التأكد من وجود عنوان IP في حقل IP Device'));
        }
    }
});

