frappe.ui.form.on('taq_data1', {
    validate: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.throw(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
        }
    },
    agee: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.msgprint(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
            frm.set_value('agee', '');  // يمسح العمر المدخل
        }
    }
});

frappe.ui.form.on('taq_data1', {
    refresh: function(frm) {

        // زر الإحالة في taq_data1
        if(!frm.doc.taq_referred) {
            frm.add_custom_button(__('إحالة للجنة قبول الوعاظ'), function() {

                let new_doc = {
                    doctype: "lagna_taq",
                    nameee: frm.doc.name,         
                    nameee_display: frm.doc.namee, 
                    makteeeb: frm.doc.makteeb,      
                    taq_data1_ref: frm.doc.name,    
                    taq_data1_id: frm.doc.name,     
                    taq_referred_status: 1          
                };

                frappe.call({
                    method: "frappe.client.insert",
                    args: { doc: new_doc },
                    callback: function(r) {
                        if(!r.exc && r.message) {
                            frappe.msgprint(__('تمت الإحالة إلى لجنة قبول الوعاظ'));

                            frappe.db.set_value(frm.doctype, frm.doc.name, 'taq_referred', 1);

                            frappe.set_route("Form", "lagna_taq", r.message.name);
                        }
                    }
                });
            });
        }
    }
});

frappe.ui.form.on('lagna_taq', {
    refresh: function(frm) {

        // إزالة أي أزرار قديمة بنفس الاسم
        frm.clear_custom_buttons();

        // إضافة زر "عرض التفاصيل" فقط إذا كان هناك مرجع
        if(frm.doc.taq_data1_ref) {
            frm.add_custom_button(__('عرض التفاصيل'), function() {
                frappe.set_route("Form", "taq_data1", frm.doc.taq_data1_ref);
            });
        }
    }
});

frappe.ui.form.on('lagna_taq', {
    refresh: function(frm) {
        if (!frm.doc.moq) {
            frm.set_value('moq', frappe.session.user);
        }
    }
});

