frappe.ui.form.on('Issue', {
    onload: function(frm) {
        // جلب اسم المستخدم الحالي
        if (!frm.doc.user_account) {
            frm.set_value('user_account', frappe.session.user);
        }

        // جلب اسم المرسل من DocType User
        frappe.db.get_value('User', frappe.session.user, 'full_name', (r) => {
            if (r && r.full_name) {
                frm.set_value('sender_name', r.full_name);
            }
        });

        // محاولة جلب اسم الجهاز و IP (يحتاج صلاحيات Client-side)
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "User",
                filters: { "name": frappe.session.user },
                fieldname: ["last_ip"]
            },
            callback: function(r) {
                if (r.message && r.message.last_ip) {
                    frm.set_value('device_ip', r.message.last_ip);
                }
            }
        });

        // جلب اسم الجهاز من الـ browser
        try {
            frm.set_value('device_name', window.navigator.userAgent);
        } catch (e) {
            console.log("Error fetching device name:", e);
        }

        // لا يمكن جلب MAC من المتصفح مباشرة (محظور أمنيًا)
        frm.set_df_property('device_mac', 'description', 'يتم تعبئتها يدويًا لأسباب أمان المتصفح');
    }
});

frappe.ui.form.on('اسم_DocType', {
    refresh: function(frm) {
        generate_map(frm);
    },
    الموقع_الخاص_بالمكتب: function(frm) {
        generate_map(frm);
    }
});

function generate_map(frm) {
    if(!frm.doc.الموقع_الخاص_بالمكتب) return;

    try {
        // تحويل GeoJSON إلى إحداثيات
        let geojson = JSON.parse(frm.doc.الموقع_الخاص_بالمكتب);
        let coords = geojson.features[0].geometry.coordinates;
        let lat = coords[1];
        let lng = coords[0];

        let api_key = "YOUR_API_KEY"; // ضع مفتاح Google Maps الخاص بك هنا
        let url = `https://maps.googleapis.com/maps/api/staticmap?center=${lat},${lng}&zoom=15&size=600x300&markers=color:red|${lat},${lng}&key=${api_key}`;

        // جلب الصورة وتحويلها إلى Base64
        fetch(url)
            .then(response => response.blob())
            .then(blob => {
                let reader = new FileReader();
                reader.onloadend = function() {
                    let base64data = reader.result.split(',')[1]; // الحصول على Base64 فقط
                    frm.set_value('map_base64', base64data);
                    frm.save(); // حفظ تلقائي للتحديث
                }
                reader.readAsDataURL(blob);
            })
            .catch(err => {
                frappe.msgprint("خطأ في توليد الخريطة: " + err);
            });
    } catch(e) {
        frappe.msgprint("خطأ في تحليل الموقع: " + e.message);
    }
}

