function toggle_relation_field(frm) {
    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;

    if (kitchen === "مطبخ مفتوح" || living === "فراغ مفتوح") {
        frm.set_df_property("relation_type", "hidden", 0);
        $('#ui_relation_type_wrapper').fadeIn();
    } else {
        frm.set_df_property("relation_type", "hidden", 1);
        frm.set_value("relation_type", "");
        $('#ui_relation_type_wrapper').fadeOut();
        $('#ui_relation_type').val("");
    }
}

function suggest_relation(frm) {
    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;
    let dining = frm.doc.dining_type;
    let suggestion = "";

    if (kitchen === "مطبخ مفتوح" && living === "فراغ مفتوح" && dining === "فراغ مفتوح") {
        suggestion = "المعيشة مفتوحة على المطبخ والأكل";
    } else if (living === "فراغ مفتوح" && dining === "فراغ مفتوح") {
        suggestion = "المعيشة مفتوحة على الأكل";
    } else if (kitchen === "مطبخ مفتوح" && living === "فراغ مفتوح") {
        suggestion = "مطبخ مفتوح على المعيشة";
    } else if (kitchen === "مطبخ مفتوح" && dining === "فراغ مفتوح") {
        suggestion = "مطبخ مفتوح على الأكل";
    }

    if (suggestion !== "") {
        frm.set_value("relation_type", suggestion);
        $('#ui_relation_type').val(suggestion);
    }
}

