        const child_tables = {
            'table_ujcq': '#custom_table_ujcq',
            'kha': '#custom_kha',
            'adwaar': '#custom_adwaar',
            'masaha': '#custom_masaha',
            'moj': '#custom_moj',
            'spa': '#custom_spa',
            'far': '#custom_far',
            'est': '#custom_est',
            'mala': '#custom_mala',
            'salalem': '#custom_salalem',
            'taj': '#custom_taj',
            'mada': '#custom_mada',
            'masa': '#custom_masa',
            'hade': '#custom_hade'
        };

        for (let tbl in child_tables) {
            if (frm.fields_dict[tbl] && frm.fields_dict[tbl].wrapper) {
                $(frm.fields_dict[tbl].wrapper).appendTo(wrapper.$wrapper.find(child_tables[tbl]));
            }
        }

        $(window).trigger('resize');
    }, 500);

    bind_survey_events(frm, wrapper.$wrapper);
}

function sync_values_to_ui(frm, $wrapper) {
    const text_fields = [
        'full_name', 'phone', 'email', 'current_residence', 'city', 
        'project_location', 'couples', 'grandchildren', 'boys_under_10', 
        'girls_under_10', 'boys_above_14', 'girls_above_14', 'special_needs_details',
        'husband_job', 'wife_job', 'هل_هناك_أي_شي_إضافي_تريده_ولم_يذكر_في_هدا_الاستبيان'
    ];
    text_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).val(frm.doc[field] || '');
    });

    const radio_fields = ['has_sketch', 'has_autocad', 'size_family', 'haya'];
    radio_fields.forEach(field => {
        $wrapper.find(`input[name="${field}"]`).prop('checked', false);
        if(frm.doc[field]) {
            $wrapper.find(`input[name="${field}"][value="${frm.doc[field]}"]`).prop('checked', true);
        }
    });

    const select_fields = [
        'travel', 'has_special_needs', 'tasneef', 'sor', 'manaseb', 
        'farq', 'rasef', 'living_type', 'kitchen_type', 'dining_type', 'relation_type',
        'need_office', 'هل_تحتاج_مساحة_عمل_إضافية'
    ];
    select_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).val(frm.doc[field] || '');
    });

    if (frm.doc.has_special_needs === 'نعم') {
        $wrapper.find('#ui_special_needs_details_wrapper').show();
    } else {
        $wrapper.find('#ui_special_needs_details_wrapper').hide();
    }
}

function bind_survey_events(frm, $wrapper) {
    const text_fields = [
        'full_name', 'phone', 'email', 'current_residence', 'city', 
        'project_location', 'couples', 'grandchildren', 'boys_under_10', 
        'girls_under_10', 'boys_above_14', 'girls_above_14', 'special_needs_details',
        'husband_job', 'wife_job', 'هل_هناك_أي_شي_إضافي_تريده_ولم_يذكر_في_هدا_الاستبيان'
    ];
    text_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('input change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    const radio_fields = ['has_sketch', 'has_autocad', 'size_family', 'haya'];
    radio_fields.forEach(field => {
        $wrapper.find(`input[name="${field}"]`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    const select_fields = [
        'travel', 'has_special_needs', 'tasneef', 'sor', 'manaseb', 
        'farq', 'rasef', 'living_type', 'kitchen_type', 'dining_type', 'relation_type',
        'need_office', 'هل_تحتاج_مساحة_عمل_إضافية'
    ];
    select_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('change', function() {
            frm.set_value(field, $(this).val());

            if (field === 'has_special_needs') {
                if ($(this).val() === 'نعم') {
                    $('#ui_special_needs_details_wrapper').slideDown();
                } else {
                    $('#ui_special_needs_details_wrapper').slideUp();
                    $('#ui_special_needs_details').val('');
                    frm.set_value('special_needs_details', '');
                }
            }
        });
    });
}

frappe.ui.form.on("Quotation", {
    // ✅ تم حذف refresh لتجنب مشكلة Not Saved بعد الحفظ
    intro_section: function(frm) { build_content(frm); },
    project_desc_section: function(frm) { build_content(frm); },
    technical_section: function(frm) { build_content(frm); },
    phase1: function(frm) { build_content(frm); },
    phase2: function(frm) { build_content(frm); },
    phase3: function(frm) { build_content(frm); },
    price_from: function(frm) { build_content(frm); },
    price_to: function(frm) { build_content(frm); },
    total_from: function(frm) { build_content(frm); },
    total_to: function(frm) { build_content(frm); }
});

function build_content(frm) {

    let map = {
        "مقدمة": "intro_section",
        "وصف المشروع": "project_desc_section",
        "العرض الفني": "technical_section",
        "المرحلة الأولى": "phase1",
        "المرحلة الثانية": "phase2",
        "المرحلة الثالثة": "phase3",
        "العرض المالي": "financial_section"
    };

    let selected = [];

    for (let title in map) {
        if (frm.doc[map[title]]) {
            selected.push(title);
        }
    }

    // ===================================
    // إذا لا يوجد أي اختيار
    // ===================================
    if (!selected.length) {
        // ✅ لا يتم التحديث إلا إذا كان الحقل يحتوي فعلاً على قيمة
        if (frm.doc.technical_content) {
            frm.set_value("technical_content", "");
        }
        return;
    }

    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Technical Template",
            filters: {
                title: ["in", selected]
            },
            fields: ["title", "content"]
        },

        callback: function(r) {

            // تم إضافة الـ CSS المخصص للخطوط المائلة هنا
            let html = `
                <style>
                    .custom-title-box {
                        position: relative !important;
                        display: inline-block !important;
                        background-color: #000000 !important;
                        color: #ffffff !important;
                        padding: 4px 15px !important;
                        font-weight: bold !important;
                        font-size: 15px !important;
                        border-radius: 2px !important;
                        z-index: 5 !important;
                    }
                    .custom-title-box::after {
                        content: "" !important;
                        position: absolute !important;
                        top: 0 !important;
                        right: 100% !important;
                        width: 1500px !important;
                        height: 100% !important;
                        background-image: repeating-linear-gradient(45deg, #000000, #000000 2px, transparent 2px, transparent 6px) !important;
                        -webkit-print-color-adjust: exact !important;
                        print-color-adjust: exact !important;
                        z-index: -1 !important;
                    }
                </style>
                <div style="
                    direction: rtl;
                    text-align: justify;
                    font-family: Tahoma, Arial, sans-serif;
                    font-size: 14px;
                    line-height: 1.8;
                    color: #000;
                    overflow-x: hidden;
                ">
            `;

            let results = r.message || [];
            let ordered_results = [];

            selected.forEach(sel => {
                let match = results.find(d => d.title === sel);
                if (match) {
                    ordered_results.push(match);
                }
            });

            ordered_results.forEach(d => {

                let text = d.content || "";

                // ===================================
                // استبدال المتغيرات (كما أرسلتها أنت بالضبط)
                // ===================================
                text = text.replace(/{{customer_name}}/g, frm.doc.customer_name || "");
                text = text.replace(/{{project}}/g, frm.doc.project_name || "");
                text = text.replace(/{{land_area}}/g, frm.doc.land_area || "");
                text = text.replace(/{{price_from}}/g, frm.doc.price_from || "");
                text = text.replace(/{{price_to}}/g, frm.doc.price_to || "");
                text = text.replace(/{{total_from}}/g, frm.doc.total_from || "");
                text = text.replace(/{{total_to}}/g, frm.doc.total_to || "");

                // ===================================
                // تصميم الأقسام (الشرط كما وضعته أنت تماماً)
                // ===================================
                if (
                    d.title === "مقدمة" ||
                    d.title === "وصف المشروع"
                ) {
                    html += `
                        <div style="margin-bottom: 25px;">
                            <div style="
                                font-weight: bold;
                                font-size: 15px;
                                margin-bottom: 5px;
                            ">
                                ${d.title}:
                            </div>

                            <div style="padding-right: 15px;">
                                ${text}
                            </div>
                        </div>
                    `;
                } else {
                    html += `
                        <div style="margin-bottom: 25px;">

                            <div style="margin-bottom: 10px;">
                                <!-- استخدام كلاس التصميم الذي يحتوي على المربع والخطوط المائلة -->
                                <span class="custom-title-box">
                                    ${d.title}
                                </span>
                            </div>

                            <div style="padding-right: 15px;">
                                ${text}
                            </div>

                        </div>
                    `;
                }

            });

            html += "</div>";

            // ✅ أهم شرط: لا يتم التحديث إلا إذا كان المحتوى مختلف فعلاً
            if (frm.doc.technical_content !== html) {
                frm.set_value("technical_content", html);
            }
        }
    });
}

