});


frappe.ui.form.on("Quotation Item", {
    land_area: function(frm, cdt, cdn) {
        calculate_totals(frm);
    },

    price_from: function(frm, cdt, cdn) {
        calculate_totals(frm);
    },

    price_to: function(frm, cdt, cdn) {
        calculate_totals(frm);
    },

    items_remove: function(frm) {
        calculate_totals(frm);
    }
});


// ===================================
// 💰 حساب الإجمالي من الـ Items
// ===================================
function calculate_totals(frm) {

    let total_from = 0;
    let total_to = 0;

    (frm.doc.items || []).forEach(row => {

        let area = row.land_area || 0;
        let from = row.price_from || 0;
        let to = row.price_to || 0;

        total_from += area * from;
        total_to += area * to;
    });

    // ✅ لا يتم التحديث إلا إذا تغيرت القيمة فعلاً
    if (frm.doc.total_from !== total_from) {
        frm.set_value("total_from", total_from);
    }

    if (frm.doc.total_to !== total_to) {
        frm.set_value("total_to", total_to);
    }

    build_financial_and_technical(frm);
}


// ===================================
// 🧾 بناء العرض المالي داخل النص
// ===================================
function build_financial_and_technical(frm) {

    let content = frm.doc.technical_content || "";

    // حذف العرض المالي القديم
    content = content.replace(
        /<div class="financial-block">[\s\S]*?<\/div>/g,
        ""
    );

    // إذا التشيك غير مفعل → نحذف فقط
    if (!frm.doc.financial_section) {

        // ✅ تحديث فقط عند وجود فرق
        if (frm.doc.technical_content !== content) {
            frm.set_value("technical_content", content);
        }

        return;
    }

    // نأخذ أول Item فقط لعرض سعر المتر
    let first_item = (frm.doc.items || [])[0] || {};

    let financial_html = `
    <div class="financial-block">
        <h3>العرض المالي</h3>

        <p>
        سعر المتر المربع يتراوح بين
        <strong>${first_item.price_from || 0}</strong>
        إلى
        <strong>${first_item.price_to || 0}</strong>
        دينار
        </p>

        <p>
        وبناءً عليه فإن التكلفة الإجمالية تتراوح بين:
        </p>

        <p>
        <strong>${frm.doc.total_from || 0}</strong>
        إلى
        <strong>${frm.doc.total_to || 0}</strong>
        دينار
        </p>
    </div>
    `;

    let final_content = content + financial_html;

    // ✅ تحديث فقط إذا النص فعلاً مختلف
    if (frm.doc.technical_content !== final_content) {
        frm.set_value("technical_content", final_content);
    }
}
